css:
/* 全局背景和字体 */

@import url("https://fontsapi.zeoseven.com/19/main/result.css");

body {
    font-family: "LXGW Neo XiHei";
    font-weight: normal;
}

  :root {
    --avatar-base-width: 48px;
    --avatar-base-height: 48px;
    --avatar-base-border-radius: 6px;
    --black30a: #ffffff10 !important;
    --warning: #ce3636;
    --crimson70a: #0252ff66;
    --crimson-hover: #2a60d5ba;
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
  }

  /* 聊天框背景 */
  #chat {
    padding: 8px;
  }

  #top-settings-holder {
    background-color: var(--SmartThemeChatTintColor);
    box-shadow: 0 1px 0 0 #3b352d;
  }

  /* Icon Sizes */
  .custom-drawer-icon, .inline-drawer-icon, .drawer-icon, #rm_button_characters, #rm_button_panel_pin_div {
    font-size: calc(var(--mainFontSize)* 1.2);
  }

  #lm_button_panel_pin_div {
    font-size: calc(var(--mainFontSize)* 1.2);
  }

  .drawer-content {
    border-top-right-radius: 0px;
    border-top-left-radius: 0px;
    box-shadow: 0 1px 0 0 #3b352d;
    padding-top: 8px;
  }

  /* 标题样式 */
  #extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader {
    background-image: none !important;
    padding: 2px 0px !important;
  }

  .redOverlayGlow {
    color: #9c2c2c;
  }

  /* AI聊天气泡样式 */
  body.bubblechat .mes[is_user="false"]{
    margin-top: 8px;
    margin-bottom: 16px;
  }

  /* 聊天气泡 */
  body.bubblechat .mes {
    border-radius: 10px;
    padding: 16px 16px;
    display: flex;
    flex-direction: column;
  }

  /* 头像 */
  .mesAvatarWrapper {
    display: flex;
    flex-direction: row; /* 从竖排改成横排 */
    align-items: center; /* 垂直居中 */
    gap: 8px; /* 头像和气泡之间的间距 */
    background-color: #ffffff0b;
    padding: 8px; /* 间距 */
    padding-right: 12px; /* 右侧间距 */
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
    overflow: hidden;
    width: 100%;
  }

    /* 头像处理 */
  .mes .avatar img{
   padding: 0px;
  }

  .avatar img {
    border: none;
    box-shadow: none !important;
  }

    /* 名字 */
  .mes_block .ch_name {
    background-color: #ffffff0b;
    border-bottom-left-radius: 8px;
    border-bottom-right-radius: 8px;
    padding: 8px; /* 间距 */
    margin-bottom: 12px;
  }

    /* 正文 */
  .mes_text {
    padding: 0px 4px !important;
  }

  .last_mes .mesAvatarWrapper {
    padding-bottom: 8px !important;
}
  .mes_block {
    padding-left: 0px !important;
  }

  /* 快捷回复 */
  .menu_button  {
    background-color: #ececee10;
    border-radius: 4px !important;
  }

  /* 发送bar */
  #send_form {
    border-top: #ab9c8551 solid 1px;
  }

  /* 拓展按钮 */
  #extensionsMenu, .options-content {
    background-color: var(--SmartThemeChatTintColor);
  }

  .menu_button.menu_button_default {
    box-shadow: none !important;
  }

  /* 滑轮 */
  input[type="range"] {
    box-shadow: none;
    background-color: var(--black30a) !important;
    height: 5px;
  }

  /* Checkbox */
  input[type='checkbox'] {
    background-color: #ffffff2b;
    border: none;
    box-shadow: none;
    border-radius: 2px;
  }
  input[type="checkbox"]::before {
    box-shadow: inset 1em 1em var(--SmartThemeEmColor);
  }

  /* 预设 */
  #completion_prompt_manager_list {
    background-color: #161618;
    padding: 0px 8px;
  }

  #completion_prompt_manager .caution {
    color: var(--warning);
  }

  #completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    background-color: #1c1c1e;
    border: none;
    border-radius: 2px;
    padding: 8px;
    margin-bottom: 8px;
  }
  #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
    background-color: #161618;
    border: none;
    border-radius: 2px;
    padding: 8px;
    margin-bottom: 8px;
  }

  /* Spacing Adjustment */
  .range-block-title {
    margin: 8px 0px;
    text-align: left;
  }

  hr {
    background-image: none;
    background-color: var(--SmartThemeUnderlineColor);
    margin: 12px 0px;
  }

  .range-block {
    margin-bottom: 8px;
  }
  .checkbox_label {
    margin: 2px 0px;
  }
  input[type="range"]::-webkit-slider-thumb {
    box-shadow: none;
    background-color: var(--SmartThemeEmColor);
    width: 12px;
    height: 12px;
  }

  #result_info_text {
    color: var(--SmartThemeBodyColor);
  }

  .editable-slider-notification {
    height: 20px;
  }

  #version_display {
    max-width: 70px !important;
  }

  select {
    margin: 5px 0 !important;
  }

  #userSettingsRowOne {
    margin: 8px 0px;
  }

  .mes_reasoning_header_title {
    padding-right: 16px;
  }

  #rm_print_characters_block {
    margin-top: 8px;
  }

  #ui_language_select {
    width: 6em !important;
 }

  /* 角色 */
  #rm_button_selected_ch h2 {
    padding-bottom: 8px;
  }
  #rm_print_characters_pagination {
    background-color: var(--SmartThemeChatTintColor);
    border-radius: 8px;
    padding: 8px;
    margin: 8px;
  }
  .avatar-container.selected {
    border: 1px solid var(--SmartThemeUnderlineColor);
    border-radius: 4px;
  }

  .avatar-container:hover {
    background-color: var(--white20a);
}

  /* thinking */
  .mes_reasoning_header {
    background-color: #ffffff18;
    justify-content: center;
    padding: 8px;
  }

  .mes_reasoning_details .mes_reasoning_arrow {
    height: var(--mainFontSize)*0.9;
    width: var(--mainFontSize)*0.9;
  }

  .mes_reasoning {
    border-left: var(--SmartThemeUnderlineColor) solid 2px;
    color: var(--SmartThemeBodyColor)
  }

  /* scrollbar */
  ::-webkit-scrollbar {
    width: 7px;
  }

  .drawer-content .alignItemsBaseline {
    align-items: center !important;
  }

  .flex1.flex-container.alignItemsBaseline {
    min-width: 214px;
  }

  .flex-container.flexnowrap.alignitemscenter, .flex-container.alignItemsBaseline.wide100p, .flex-container.alignitemscenter.gap10px, .flex-container.alignItemsBaseline, .alignitemscenter.flex-container.wide100p {
    margin: 5px 0px;
  }

  .fa-solid.fa-circle-question.note-link-span {
    padding-top: 5px;
    padding-bottom: 5px;
  }

  .doubleRangeContainer > .doubleRangeInputContainer::after {
    background-color: var(--SmartThemeEmColor);
    box-shadow: none !important;
  } 

  /* pagination */
  div[is_user="false"].last_mes .mes_block {
    padding-bottom: 48px;
  }

.mes_text q {
    color: var(--SmartThemeQuoteColor);
    background-color: #faffdf14;
    margin: 0px 3px;
    padding: 2px 4px;
    padding-left: 8px;
    border-radius: 2px;
    border-left: #faffdf61 1.5px solid;
    border-right: #faffdf61 1.5px solid;
    font-size: calc(0.97* var(--mainFontSize));
}
